            deviceMap[record.device_name] = record;
        }
    });

    const colors = {
        'TV': '#ff6b9d',
        'Router': '#c77dff',
        'Charger': '#4ecdc4',
        'Refrigerator': '#ffd166'
    };

    const devices = Object.values(deviceMap).sort((a, b) => b.power_watts - a.power_watts);

    let html = '';
    devices.forEach(device => {
